   220→// ============================================================================
   221→// Parade - Display comprehensive Heat status for project review
   222→// ============================================================================
   223→
   224→/// Output format modes for parade command
   225→#[derive(Debug, Clone, Copy, Default, PartialEq, Eq)]
   226→pub enum jjrq_ParadeFormat {
   227→    /// One line per pace: [state] silks (₢coronet)
   228→    Overview,
   229→    /// Numbered list: N. [state] silks (₢coronet)
   230→    Order,
   231→    /// Full tack text for one pace (requires --pace)
   232→    Detail,
   233→    /// Paddock + all paces with tack text (default)
   234→    #[default]
   235→    Full,
   236→}
   237→
   238→/// Arguments for parade command
   239→#[derive(Debug)]
   240→pub struct jjrq_ParadeArgs {
   241→    pub file: std::path::PathBuf,
   242→    pub firemark: Firemark,
   243→    pub format: jjrq_ParadeFormat,
   244→    pub pace: Option<String>,
   245→    pub remaining: bool,
   246→}
   247→
   248→/// Run the parade command - display comprehensive Heat status
   249→pub fn jjrq_run_parade(args: jjrq_ParadeArgs) -> i32 {
   250→    // Validate: detail format requires --pace
   251→    if args.format == jjrq_ParadeFormat::Detail && args.pace.is_none() {
   252→        eprintln!("jjx_parade: error: --format detail requires --pace <coronet>");
   253→        return 1;
   254→    }
   255→
   256→    let gallops = match Gallops::jjrg_load(&args.file) {
   257→        Ok(g) => g,
   258→        Err(e) => {
   259→            eprintln!("jjx_parade: error: {}", e);
   260→            return 1;
   261→        }
   262→    };
   263→
   264→    let heat_key = args.firemark.jjrf_display();
   265→    let heat = match gallops.heats.get(&heat_key) {
   266→        Some(h) => h,
   267→        None => {
   268→            eprintln!("jjx_parade: error: Heat '{}' not found", heat_key);
   269→            return 1;
   270→        }
   271→    };
   272→
   273→    match args.format {
   274→        jjrq_ParadeFormat::Overview => {
   275→            for coronet_key in &heat.order {
   276→                if let Some(pace) = heat.paces.get(coronet_key) {
   277→                    if let Some(tack) = pace.tacks.first() {
   278→                        // Skip complete/abandoned if --remaining
   279→                        if args.remaining && (tack.state == PaceState::Complete || tack.state == PaceState::Abandoned) {
   280→                            continue;
   281→                        }
   282→                        let state_str = zjjrq_pace_state_str(&tack.state);
   283→                        println!("[{}] {} ({})", state_str, tack.silks, coronet_key);
   284→                    }
   285→                }
   286→            }
   287→        }
   288→        jjrq_ParadeFormat::Order => {
   289→            let mut num = 0;
   290→            for coronet_key in &heat.order {
   291→                if let Some(pace) = heat.paces.get(coronet_key) {
   292→                    if let Some(tack) = pace.tacks.first() {
   293→                        // Skip complete/abandoned if --remaining
   294→                        if args.remaining && (tack.state == PaceState::Complete || tack.state == PaceState::Abandoned) {
   295→                            continue;
   296→                        }
   297→                        num += 1;
   298→                        let state_str = zjjrq_pace_state_str(&tack.state);
   299→                        println!("{}. [{}] {} ({})", num, state_str, tack.silks, coronet_key);
   300→                    }
   301→                }
   302→            }
   303→        }
   304→        jjrq_ParadeFormat::Detail => {
   305→            let pace_arg = args.pace.as_ref().unwrap();
   306→            let (coronet_key, pace) = match zjjrq_resolve_pace(heat, pace_arg) {
   307→                Some(result) => result,
   308→                None => {
   309→                    eprintln!("jjx_parade: error: Pace '{}' not found in Heat '{}' (tried coronet and silks)", pace_arg, heat_key);
   310→                    return 1;
   311→                }
   312→            };
   313→            if let Some(tack) = pace.tacks.first() {
   314→                let state_str = zjjrq_pace_state_str(&tack.state);
   315→                println!("Pace: {} ({})", tack.silks, coronet_key);
   316→                println!("State: {}", state_str);
   317→                println!("Heat: {}", heat_key);
   318→                println!();
   319→                println!("{}", tack.text);
   320→                if let Some(ref direction) = tack.direction {
   321→                    println!();
   322→                    println!("Direction: {}", direction);
   323→                }
   324→            }
   325→        }
   326→        jjrq_ParadeFormat::Full => {
   327→            // Read paddock file content
   328→            let paddock_content = match fs::read_to_string(&heat.paddock_file) {
   329→                Ok(content) => content,
   330→                Err(e) => {
   331→                    eprintln!("jjx_parade: error reading paddock file '{}': {}", heat.paddock_file, e);
   332→                    return 1;
   333→                }
   334→            };
   335→
   336→            let status_str = match heat.status {
   337→                HeatStatus::Racing => "racing",
   338→                HeatStatus::Stabled => "stabled",
   339→                HeatStatus::Retired => "retired",
   340→            };
   341→
   342→            println!("Heat: {} ({})", heat.silks, heat_key);
   343→            println!("Status: {}", status_str);
   344→            println!("Created: {}", heat.creation_time);
   345→            println!();
   346→            println!("## Paddock");
   347→            println!();
   348→            println!("{}", paddock_content);
   349→            println!();
   350→            println!("## Paces");
   351→            println!();
   352→
   353→            for coronet_key in &heat.order {
   354→                if let Some(pace) = heat.paces.get(coronet_key) {
   355→                    if let Some(tack) = pace.tacks.first() {
   356→                        // Skip complete/abandoned if --remaining
   357→                        if args.remaining && (tack.state == PaceState::Complete || tack.state == PaceState::Abandoned) {
   358→                            continue;
   359→                        }
   360→                        let state_str = zjjrq_pace_state_str(&tack.state);
   361→                        println!("### {} ({}) [{}]", tack.silks, coronet_key, state_str);
   362→                        println!();
   363→                        println!("{}", tack.text);
   364→                        if let Some(ref direction) = tack.direction {
   365→                            println!();
   366→                            println!("**Direction:** {}", direction);
   367→                        }
   368→                        println!();
   369→                    }
   370→                }
   371→            }
   372→        }
   373→    }
   374→
   375→    0
   376→}
   377→
   378→/// Helper to resolve pace by coronet or silks
   379→///
   380→/// First tries to parse pace_arg as a Coronet and lookup by coronet key.
   381→/// If that fails, iterates heat.paces to find a pace where tacks[0].silks matches pace_arg.
   382→/// Returns tuple of (coronet_key, pace_ref) if found.
   383→fn zjjrq_resolve_pace<'a>(
   384→    heat: &'a crate::jjrg_gallops::jjrg_Heat,
   385→    pace_arg: &str,
   386→) -> Option<(&'a String, &'a Pace)> {
   387→    // Try parsing as Coronet first
   388→    if let Ok(coronet) = Coronet::jjrf_parse(pace_arg) {
   389→        let coronet_key = coronet.jjrf_display();
   390→        if let Some((key, pace)) = heat.paces.get_key_value(&coronet_key) {
   391→            return Some((key, pace));
   392→        }
   393→    }
   394→
   395→    // Fallback: search by silks
   396→    for (coronet_key, pace) in &heat.paces {
   397→        if let Some(tack) = pace.tacks.first() {
   398→            if tack.silks == pace_arg {
   399→                return Some((coronet_key, pace));
   400→            }
   401→        }
   402→    }
   403→
   404→    None
   405→}
   406→
   407→/// Helper to convert PaceState to display string
   408→fn zjjrq_pace_state_str(state: &PaceState) -> &'static str {
   409→    match state {
   410→        PaceState::Rough => "rough",
   411→        PaceState::Bridled => "bridled",
   412→        PaceState::Complete => "complete",
   413→        PaceState::Abandoned => "abandoned",
   414→    }
   415→}
