   437→    pub(crate) paces: Vec<zjjrq_RetirePace>,
   438→    // TODO: steeplechase array from jjx_rein
   439→    // steeplechase: Vec<SteeplechaseEntry>,
   440→}
   441→
   442→/// Pace structure for retire output (full tack history)
   443→#[derive(Serialize)]
   444→pub(crate) struct zjjrq_RetirePace {
   445→    pub(crate) coronet: String,
   446→    pub(crate) silks: String,
   447→    pub(crate) tacks: Vec<zjjrq_RetireTack>,
   448→}
   449→
   450→/// Tack structure for retire output
   451→#[derive(Serialize)]
   452→pub(crate) struct zjjrq_RetireTack {
   453→    pub(crate) ts: String,
   454→    pub(crate) state: String,
   455→    pub(crate) text: String,
   456→    #[serde(skip_serializing_if = "Option::is_none")]
   457→    pub(crate) direction: Option<String>,
   458→}
   459→
   460→/// Run the retire command - extract complete Heat data for archival
   461→pub fn jjrq_run_retire(args: jjrq_RetireArgs) -> i32 {
   462→    let gallops = match Gallops::jjrg_load(&args.file) {
   463→        Ok(g) => g,
   464→        Err(e) => {
   465→            eprintln!("jjx_retire: error: {}", e);
   466→            return 1;
   467→        }
   468→    };
   469→
   470→    let heat_key = args.firemark.jjrf_display();
   471→    let heat = match gallops.heats.get(&heat_key) {
   472→        Some(h) => h,
   473→        None => {
   474→            eprintln!("jjx_retire: error: Heat '{}' not found", heat_key);
   475→            return 1;
   476→        }
   477→    };
   478→
   479→    // Read paddock file content
   480→    let paddock_content = match fs::read_to_string(&heat.paddock_file) {
   481→        Ok(content) => content,
   482→        Err(e) => {
   483→            eprintln!("jjx_retire: error reading paddock file '{}': {}", heat.paddock_file, e);
   484→            return 1;
   485→        }
   486→    };
   487→
   488→    // Build paces array with full tack history, ordered per Heat's order array
   489→    let mut paces = Vec::new();
   490→    for coronet_key in &heat.order {
   491→        if let Some(pace) = heat.paces.get(coronet_key) {
   492→            let tacks: Vec<zjjrq_RetireTack> = pace.tacks.iter().map(|tack| {
   493→                zjjrq_RetireTack {
   494→                    ts: tack.ts.clone(),
   495→                    state: match tack.state {
   496→                        PaceState::Rough => "rough".to_string(),
   497→                        PaceState::Bridled => "bridled".to_string(),
   498→                        PaceState::Complete => "complete".to_string(),
   499→                        PaceState::Abandoned => "abandoned".to_string(),
   500→                    },
   501→                    text: tack.text.clone(),
   502→                    direction: tack.direction.clone(),
   503→                }
   504→            }).collect();
   505→
   506→            paces.push(zjjrq_RetirePace {
   507→                coronet: coronet_key.clone(),
   508→                silks: pace.tacks.first().map(|t| t.silks.clone()).unwrap_or_default(),
   509→                tacks,
   510→            });
   511→        }
   512→    }
   513→
   514→    let output = zjjrq_RetireOutput {
   515→        firemark: heat_key.clone(),
